#!/usr/bin/env python3
"""
Secure Database Connection Health Monitor for Prometheus
Exports connection health metrics WITHOUT exposing credentials
"""

import os
import hashlib
import time
from prometheus_client import Gauge, start_http_server
from typing import Dict, Optional
import psycopg2
import mysql.connector
from urllib.parse import urlparse
import logging

# Configure secure logging (no sensitive data)
logging.basicConfig(level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')
logger = logging.getLogger(__name__)

class SecureDatabaseMonitor:
    """
    Monitors database connection health and exports metrics to Prometheus
    WITHOUT exposing credentials in metric labels
    """
    
    def __init__(self):
        # Metrics use only non-sensitive identifiers
        self.connection_health = Gauge(
            'database_connection_health',
            'Database connection health status (1=healthy, 0=unhealthy)',
            ['db_identifier', 'db_type', 'host_hash']
        )
        
        self.connection_latency = Gauge(
            'database_connection_latency_seconds',
            'Database connection latency in seconds',
            ['db_identifier', 'db_type', 'host_hash']
        )
        
        self.last_check_timestamp = Gauge(
            'database_last_check_timestamp',
            'Timestamp of last connection check',
            ['db_identifier', 'db_type', 'host_hash']
        )
        
        # Load credentials from secure sources (environment variables, secrets manager)
        self.databases = self._load_database_configs()
    
    def _load_database_configs(self) -> Dict:
        """
        Load database configurations from secure sources
        NEVER from code or version control
        """
        configs = {}
        
        # Example: Load from environment variables
        # In production, use AWS Secrets Manager, HashiCorp Vault, etc.
        db_count = int(os.getenv('DB_COUNT', '0'))
        
        for i in range(db_count):
            prefix = f'DB_{i}_'
            db_type = os.getenv(f'{prefix}TYPE')
            
            if not db_type:
                continue
            
            config = {
                'type': db_type,
                'host': os.getenv(f'{prefix}HOST'),
                'port': int(os.getenv(f'{prefix}PORT', '5432' if db_type == 'postgres' else '3306')),
                'database': os.getenv(f'{prefix}DATABASE'),
                'username': os.getenv(f'{prefix}USERNAME'),
                'password': os.getenv(f'{prefix}PASSWORD'),
                'identifier': os.getenv(f'{prefix}IDENTIFIER', f'db_{i}')
            }
            
            # Validate required fields
            if all([config['host'], config['database'], config['username'], config['password']]):
                configs[config['identifier']] = config
            else:
                logger.warning(f"Incomplete configuration for {prefix}, skipping")
        
        return configs
    
    def _hash_sensitive_value(self, value: str) -> str:
        """
        Create a non-reversible hash of sensitive values for metric labels
        Uses SHA-256 truncated for readability
        """
        return hashlib.sha256(value.encode()).hexdigest()[:16]
    
    def _test_postgres_connection(self, config: Dict) -> tuple[bool, float]:
        """Test PostgreSQL connection and measure latency"""
        start_time = time.time()
        try:
            conn = psycopg2.connect(
                host=config['host'],
                port=config['port'],
                database=config['database'],
                user=config['username'],
                password=config['password'],
                connect_timeout=5,
                sslmode='require'  # Enforce SSL/TLS
            )
            cursor = conn.cursor()
            cursor.execute('SELECT 1')
            cursor.fetchone()
            cursor.close()
            conn.close()
            latency = time.time() - start_time
            return True, latency
        except Exception as e:
            logger.error(f"PostgreSQL connection failed for {config['identifier']}: {type(e).__name__}")
            return False, time.time() - start_time
    
    def _test_mysql_connection(self, config: Dict) -> tuple[bool, float]:
        """Test MySQL connection and measure latency"""
        start_time = time.time()
        try:
            conn = mysql.connector.connect(
                host=config['host'],
                port=config['port'],
                database=config['database'],
                user=config['username'],
                password=config['password'],
                connection_timeout=5,
                ssl_disabled=False  # Enforce SSL/TLS
            )
            cursor = conn.cursor()
            cursor.execute('SELECT 1')
            cursor.fetchone()
            cursor.close()
            conn.close()
            latency = time.time() - start_time
            return True, latency
        except Exception as e:
            logger.error(f"MySQL connection failed for {config['identifier']}: {type(e).__name__}")
            return False, time.time() - start_time
    
    def check_database_health(self, identifier: str, config: Dict):
        """
        Check database health and update metrics
        Uses only non-sensitive labels
        """
        # Create non-sensitive labels
        host_hash = self._hash_sensitive_value(f"{config['host']}:{config['port']}")
        labels = {
            'db_identifier': identifier,
            'db_type': config['type'],
            'host_hash': host_hash
        }
        
        # Test connection based on database type
        if config['type'] == 'postgres':
            healthy, latency = self._test_postgres_connection(config)
        elif config['type'] == 'mysql':
            healthy, latency = self._test_mysql_connection(config)
        else:
            logger.error(f"Unsupported database type: {config['type']}")
            return
        
        # Update metrics with non-sensitive labels only
        self.connection_health.labels(**labels).set(1 if healthy else 0)
        self.connection_latency.labels(**labels).set(latency)
        self.last_check_timestamp.labels(**labels).set(time.time())
        
        logger.info(f"Health check for {identifier}: {'healthy' if healthy else 'unhealthy'}, latency: {latency:.3f}s")
    
    def run_monitoring_loop(self, interval: int = 30):
        """
        Main monitoring loop
        """
        logger.info(f"Starting database health monitoring (interval: {interval}s)")
        logger.info(f"Monitoring {len(self.databases)} database(s)")
        
        while True:
            for identifier, config in self.databases.items():
                try:
                    self.check_database_health(identifier, config)
                except Exception as e:
                    logger.error(f"Error checking {identifier}: {type(e).__name__}")
            
            time.sleep(interval)


def main():
    # Validate environment
    if os.getenv('DB_COUNT', '0') == '0':
        logger.error("No databases configured. Set DB_COUNT and DB_*_* environment variables")
        return
    
    # Start Prometheus metrics server on localhost only (use reverse proxy for external access)
    metrics_port = int(os.getenv('METRICS_PORT', '9090'))
    metrics_host = os.getenv('METRICS_HOST', '127.0.0.1')  # Localhost by default
    
    start_http_server(metrics_port, addr=metrics_host)
    logger.info(f"Prometheus metrics server started on {metrics_host}:{metrics_port}")
    
    # Start monitoring
    monitor = SecureDatabaseMonitor()
    check_interval = int(os.getenv('CHECK_INTERVAL', '30'))
    monitor.run_monitoring_loop(interval=check_interval)


